const detectPiiInAiOutput = (items: n8n.workflow.ExecutionData[]) => {
  const piiPatterns = {
    email: /\b[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Z|a-z]{2,}\b/g,
    phone: /\b(?:\+?1[-.]?)?(?:\(?[0-9]{3}\)?)[-.,\s]?[0-9]{3}[-.,\s]?[0-9]{4}\b/g,
    ssn: /\b\d{3}-?\d{2}-?\d{4}\b/g
  };

  return items.map(item => {
    const data = item.json as any;
    const piiFound: string[] = [];

    Object.values(piiPatterns).forEach(pattern => {
      const matches = JSON.stringify(data).match(pattern);
      if (matches) piiFound.push(...matches);
    });

    return {
      ...item,
      json: {
        ...data,
        _vex_pii_detected: piiFound.length > 0,
        _vex_pii_types: [...new Set(piiFound)],
        _vex_pii_count: piiFound.length
      }
    };
  });
};

return detectPiiInAiOutput($input.all());

const auditToolCalls = (items: n8n.workflow.ExecutionData[]) => {
  return items.map(item => {
    const aiOutput = item.json as any;
    const toolCalls = aiOutput.tool_calls || aiOutput.tools || [];

    const riskyParams = toolCalls.map((call: any) => {
      const params = call.function?.arguments || call.args || {};
      const paramString = JSON.stringify(params);
      const apiKeyPattern = /(api[_-]?key|token|secret|password|bearer)/i;
      const piiCount = (paramString.match(/@[^\s]+/g) || []).length;

      return {
        tool_name: call.function?.name || call.name,
        has_api_keys: apiKeyPattern.test(paramString),
        pii_emails: piiCount,
        risky: piiCount > 0 || apiKeyPattern.test(paramString)
      };
    });

    return {
      ...item,
      json: {
        ...item.json,
        _vex_tool_audit: riskyParams,
        _vex_risky_tools: riskyParams.filter((t: any) => t.risky).length
      }
    };
  });
};

return auditToolCalls($input.all());

const scanMemoryContext = (items: n8n.workflow.ExecutionData[]) => {
  return items.map(item => {
    const memory = item.json as any;
    const context = Array.isArray(memory) ? memory : [memory];

    const piiMetrics = context.reduce((acc: any, msg: any) => {
      const content = JSON.stringify(msg.content || msg.text || msg);
      acc.email_count += (content.match(/@[^\s]+/g) || []).length;
      acc.phone_count += (content.match(/\d{3}[-.]?\d{3}[-.]?\d{4}/g) || []).length;
      acc.name_count += (content.match(/[A-Z][a-z]+\s[A-Z][a-z]+/g) || []).length;
      return acc;
    }, { email_count: 0, phone_count: 0, name_count: 0 });

    const totalPii = Object.values(piiMetrics).reduce((a: number, b: number) => a + (b as number), 0);

    return {
      ...item,
      json: {
        ...item.json,
        _vex_memory_pii: piiMetrics,
        _vex_pii_leak: totalPii > 0,
        _vex_pii_total: totalPii
      }
    };
  });
};

return scanMemoryContext($input.all());

