const redactPii = (items: n8n.workflow.ExecutionData[]) => {
  const redactors = {
    email: /\b[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Z|a-z]{2,}\b/gi,
    phone: /\b(?:\+?1[-.]?)?(?:\(?[0-9]{3}\)?)[-.,\s]?[0-9]{3}[-.,\s]?[0-9]{4}\b/gi,
    ssn: /\b\d{3}-?\d{2}-?\d{4}\b/gi
  };

  const redact = (text: string): string => {
    let redacted = text;
    Object.entries(redactors).forEach(([type, pattern]) => {
      redacted = redacted.replace(pattern, `[REDACTED_${type.toUpperCase()}]`);
    });
    return redacted;
  };

  return items.map(item => {
    const data = item.json as any;
    const redactedData = JSON.parse(redact(JSON.stringify(data)));

    return {
      ...item,
      json: {
        ...redactedData,
        _vex_redacted: true,
        _vex_original_size: JSON.stringify(data).length,
        _vex_redacted_size: JSON.stringify(redactedData).length
      }
    };
  });
};

return redactPii($input.all());

const safeToolParams = (items: n8n.workflow.ExecutionData[]) => {
  return items.map(item => {
    const aiOutput = item.json as any;
    const safeTools = (aiOutput.tool_calls || []).map((call: any) => {
      const params = call.function?.arguments || call.args || {};
      const safeParams = Object.fromEntries(
        Object.entries(params).map(([key, value]) => {
          const strValue = String(value);
          const hasPii = /@[^\s]+|\d{3}[-.]?\d{3}[-.]?\d{4}/.test(strValue);
          return [key, hasPii ? `[REDACTED_${key}]` : value];
        })
      );

      return {
        ...call,
        function: {
          ...call.function,
          arguments: safeParams
        }
      };
    });

    return {
      ...item,
      json: {
        ...aiOutput,
        tool_calls: safeTools,
        _vex_tools_sanitized: true
      }
    };
  });
};

return safeToolParams($input.all());

const sanitizeMemoryContext = (items: n8n.workflow.ExecutionData[]) => {
  const PII_PATTERNS = /(@[^\s]+|\d{3}[-.]?\d{3}[-.]?\d{4}|[A-Z][a-z]+\s[A-Z][a-z]+)/gi;

  return items.map(item => {
    const memory = item.json as any;
    const sanitizedMemory = Array.isArray(memory) 
      ? memory.map((msg: any) => sanitizeMessage(msg))
      : sanitizeMessage(memory);

    function sanitizeMessage(msg: any) {
      const content = msg.content || msg.text || msg;
      return {
        ...msg,
        content: content.replace(PII_PATTERNS, '[PERSONAL_DATA]'),
        _vex_sanitized: true
      };
    }

    return {
      ...item,
      json: sanitizedMemory,
      _vex_memory_safe: true
    };
  });
};

return sanitizeMemoryContext($input.all());

