import { Vex } from '@vex_dev/sdk';

const vex = new Vex({
  projectId: 'your-project-id',
  webhookToken: process.env.VEX_WEBHOOK_TOKEN
});

// n8n Code Node after AI Agent
const monitorAiAgent = async () => {
  const aiOutput = $input.all();

  const result = await vex.check({
    framework: 'n8n',
    component: 'ai-agent',
    data: aiOutput,
    rules: ['pii-filtering', 'credential-exposure'],
    context: {
      workflowId: $workflow.id,
      nodeName: $node.name,
      executionId: $execution.id
    }
  });

  if (result.violations.length > 0) {
    // Log violations and return redacted data
    console.log('Vex blocked PII:', result.violations);
    return result.safeData;
  }

  // Pass clean data to downstream nodes
  return aiOutput;
};

return await monitorAiAgent();
